#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle malformed input - turn heater off */
    if (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller_set_safe_off(controller);
        output.timed_out = true;
        return output;
    }

    switch (input.kind) {
    case CONTROLLER_INPUT_NONE:
        /* No input - keep previous state */
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Explicit sensor timeout - fail safe */
        controller_set_safe_off(controller);
        output.timed_out = true;
        return output;
    case CONTROLLER_INPUT_TEMPERATURE:
        /* Valid temperature reading */
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        if (controller->last_valid_sensor_ms - controller->last_valid_sensor_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            /* Stale sensor data for more than 1000ms - fail safe */
            controller_set_safe_off(controller);
            output.timed_out = true;
            return output;
        }

        /* Check if we need to timeout due to stale data */
        if (controller->last_valid_sensor_ms > input.now_ms) {
            /* This shouldn't happen, but treat as timeout */
            controller_set_safe_off(controller);
            output.timed_out = true;
            return output;
        }

        /* Control policy based on temperature */
        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Below 47C - turn heater on */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* Above 52C - turn heater off (safe off) */
            controller_set_safe_off(controller);
        } else if (input.temperature_c >= CONTROLLER_TEMP_HIGH_THRESHOLD && input.temperature_c <= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* 50-52C range with rising temperature - early off (HOLDING state) */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        } else {
            /* 47 <= TEMP < 50 - hold previous safe actuator state */
            if (input.temperature_c >= CONTROLLER_TEMP_LOW_THRESHOLD && input.temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                /* In 47-49 range, preserve previous safe off state */
                controller_set_safe_off(controller);
            } else {
                /* At or above 50C but below 52C - check if rising */
                bool is_rising = input.temperature_c > controller->last_temperature_c;
                if (is_rising) {
                    /* Rising temperature in upper band - early off (HOLDING) */
                    controller->heater_on = false;
                    controller->state = CONTROLLER_STATE_HOLDING;
                } else {
                    /* Not rising - hold previous safe off state */
                    controller_set_safe_off(controller);
                }
            }
        }
        break;
    default:
        /* Unknown input kind - fail safe */
        controller_set_safe_off(controller);
        output.timed_out = true;
        return output;
    }

