"""
Thermal Chamber Hysteresis Controller Tests

Each test corresponds to an explicit acceptance bullet in docs/10_task.md.
"""

import unittest
from pathlib import Path
from components.controller.controller import (
    controller_init,
    controller_step,
    CONTROLLER_TEMP_LOW_THRESHOLD,
    CONTROLLER_TEMP_HIGH_THRESHOLD,
    CONTROLLER_TEMP_EARLY_OFF_THRESHOLD,
    CONTROLLER_SENSOR_TIMEOUT_MS,
)


class ControllerSmokeTest(unittest.TestCase):
    """Test 1: Boot leaves the heater off."""

    def test_boot_leaves_heater_off(self):
        controller = {"heater_on": False, "state": 0, "has_valid_sensor": False,
                      "last_temperature_c": 0, "last_valid_sensor_ms": 0}
        input_none = {"kind": 0, "temperature_c": 0, "now_ms": 1000}

        output = controller_step(controller, input_none)

        self.assertFalse(output.heater_on, "Heater should be off after boot")
        self.assertEqual(output.state, 0, "State should be SAFE_OFF after boot")


class LowTemperatureTest(unittest.TestCase):
    """Test 2: A low temperature such as 35 drives ACT HEATER ON."""

    def test_low_temperature_turns_heater_on(self):
        controller = {"heater_on": False, "state": 0, "has_valid_sensor": False,
                      "last_temperature_c": 0, "last_valid_sensor_ms": 0}

        # Simulate temperature sensor reading at 35C
        input_temp_35 = {"kind": 1, "temperature_c": 35, "now_ms": 1000}

        output = controller_step(controller, input_temp_35)

        self.assertTrue(output.heater_on, "Heater should be ON at 35C")
        self.assertEqual(output.state, 1, "State should be HEATING at 35C")


class HighTemperatureTest(unittest.TestCase):
    """Test 3: A temperature above the upper band such as 53 drives ACT HEATER OFF."""

    def test_high_temperature_turns_heater_off(self):
        controller = {"heater_on": False, "state": 0, "has_valid_sensor": False,
                      "last_temperature_c": 0, "last_valid_sensor_ms": 0}

        # Simulate temperature sensor reading at 53C (above upper band of 52)
        input_temp_53 = {"kind": 1, "temperature_c": 53, "now_ms": 1000}

        output = controller_step(controller, input_temp_53)

        self.assertFalse(output.heater_on, "Heater should be OFF at 53C")
        self.assertEqual(output.state, 0, "State should be SAFE_OFF at 53C")


class MidRangeHoldTest(unittest.TestCase):
    """Test 4: Inside 47..49, the controller preserves the previous safe actuator state."""

    def test_mid_range_preserves_safe_off(self):
        # Start in safe off state (heater off)
        controller = {"heater_on": False, "state": 0, "has_valid_sensor": False,
                      "last_temperature_c": 0, "last_valid_sensor_ms": 0}

        # Test at various temperatures in the 47-49 range
        for temp in [47, 48, 49]:
            input_temp = {"kind": 1, "temperature_c": temp, "now_ms": 1000}
            output = controller_step(controller, input_temp)

            self.assertFalse(output.heater_on, f"Heater should be OFF at {temp}C")
            self.assertEqual(output.state, 0, f"State should be SAFE_OFF at {temp}C")


class UpperBandRisingTest(unittest.TestCase):
    """Test 5: Near the upper band, rising temperature data causes an early ACT HEATER OFF, 
        and that anticipatory off state still counts as HOLDING."""

    def test_rising_temperature_in_upper_band(self):
        # Start in safe off state with a lower temperature
        controller = {"heater_on": False, "state": 0, "has_valid_sensor": False,
                      "last_temperature_c": 45, "last_valid_sensor_ms": 1000}

        # First step: temp is 48 (in the holding zone)
        input_temp_48 = {"kind": 1, "temperature_c": 48, "now_ms": 2000}
        output_48 = controller_step(controller, input_temp_48)

        # Heater should be off, state should be SAFE_OFF (preserve previous safe off)
        self.assertFalse(output_48.heater_on, "Heater should be OFF at 48C")

        # Second step: temp rises to 51 (in upper band, rising from 48)
        input_temp_51 = {"kind": 1, "temperature_c": 51, "now_ms": 3000}
        output_51 = controller_step(controller, input_temp_51)

        # Rising temperature in upper band should trigger early off with HOLDING state
        self.assertFalse(output_51.heater_on, "Heater should be OFF at rising 51C")
        self.assertEqual(output_51.state, 2, "State should be HOLDING when rising in upper band")


class MalformedInputTest(unittest.TestCase):
    """Test 6: Malformed input forces ACT HEATER OFF."""

    def test_malformed_input_turns_heater_off(self):
        controller = {"heater_on": True, "state": 1, "has_valid_sensor": True,
                      "last_temperature_c": 40, "last_valid_sensor_ms": 1000}

        # Simulate malformed/invalid temperature input
        input_invalid = {"kind": 2, "temperature_c": -999, "now_ms": 1000}

        output = controller_step(controller, input_invalid)

        self.assertFalse(output.heater_on, "Heater should be OFF on malformed input")
        self.assertEqual(output.state, 0, "State should be SAFE_OFF on malformed input")


class StaleSensorTest(unittest.TestCase):
    """Test 7: Stale sensor data for more than 1000 ms forces ACT HEATER OFF."""

    def test_stale_sensor_data_turns_heater_off(self):
        # Start with a valid sensor reading
        controller = {"heater_on": False, "state": 0, "has_valid_sensor": True,
                      "last_temperature_c": 40, "last_valid_sensor_ms": 1000}

        # Simulate stale data - now_ms is much larger than last_valid_sensor_ms
        # but the actual input still has a valid temperature
        input_stale = {"kind": 1, "temperature_c": 45, "now_ms": 2000}

        output = controller_step(controller, input_stale)

        self.assertFalse(output.heater_on, "Heater should be OFF on stale sensor data")


class TemperatureBoundsTest(unittest.TestCase):
    """Test: Closed-loop tests keep the chamber at or below 56 C."""

    def test_temperature_awareness(self):
        """Verify controller responds appropriately across temperature range."""

        # Test at various temperatures to ensure proper bounds checking
        test_cases = [
            (30, True, "Heating"),      # Below low threshold - heater ON
            (45, False, "Holding"),     # In holding zone - heater OFF
            (51, False, "Early off"),   # Rising in upper band - early off
            (53, False, "Safe off"),    # Above high threshold - safe off
        ]

        controller = {"heater_on": False, "state": 0, "has_valid_sensor": False,
                      "last_temperature_c": 0, "last_valid_sensor_ms": 1000}

        for temp, expected_heater_on, description in test_cases:
            input_temp = {"kind": 1, "temperature_c": temp, "now_ms": 1000}
            output = controller_step(controller, input_temp)

            # Just verify the heater state is appropriate for each temperature
            if temp < 47:
                self.assertTrue(output.heater_on, f"Should be heating at {temp}C")
            else:
                self.assertFalse(output.heater_on, f"Should not heat at {temp}C")


class StateTransitionsTest(unittest.TestCase):
    """Test: Verify state transitions are correct."""

    def test_heating_to_holding(self):
        """Verify transition from HEATING to HOLDING when temp rises into upper band."""

        # Start below threshold
        controller = {"heater_on": True, "state": 1, "has_valid_sensor": False,
                      "last_temperature_c": 40, "last_valid_sensor_ms": 1000}

        input_temp_45 = {"kind": 1, "temperature_c": 45, "now_ms": 2000}
        output = controller_step(controller, input_temp_45)

        # Should be in holding state (heater off, temp rising from low to mid)
        self.assertEqual(output.state, 2, "Should transition to HOLDING at 45C")


class UpperBandHysteresisTest(unittest.TestCase):
    """Test: Verify hysteresis behavior near upper band."""

    def test_hysteresis_preserves_safe_off(self):
        """When temp is in 47-49 range, preserve previous safe off state."""

        # Start with heater ON (simulating recovery from cold)
        controller = {"heater_on": True, "state": 1, "has_valid_sensor": False,
                      "last_temperature_c": 35, "last_valid_sensor_ms": 1000}

        # Step into holding zone (47-49C) - should preserve safe off
        input_temp_48 = {"kind": 1, "temperature_c": 48, "now_ms": 2000}
        output = controller_step(controller, input_temp_48)

        # Should be in safe off state (heater off)
        self.assertFalse(output.heater_on, "Should preserve safe off at 48C")


if __name__ == "__main__":
    unittest.main()

"""
