"""

import unittest
import subprocess
import json
from pathlib import Path


class ControllerSubprocessTest(unittest.TestCase):
    """Tests for the thermal chamber hysteresis controller."""

    def _run_controller_test(self, initial_temp=40, initial_heater=False, 
                             input_temp=None, expected_heater=True, expected_state=0):
        """Run a single controller test via subprocess."""

        # Create a test runner script
        test_script = Path(__file__).parent / "controller_runner.py"

        args = [str(test_script), "--initial-temp", str(initial_temp), 
                "--initial-heater", str(initial_heater),
                "--input-temp", str(input_temp) if input_temp is not None else "",
                "--expected-heater", str(expected_heater),
                "--expected-state", str(expected_state)]

        result = subprocess.run(
            args,
            capture_output=True,
            text=True,
            timeout=5
        )

        self.assertEqual(result.returncode, 0, f"Controller test failed: {result.stderr}")
        return result.stdout.strip()

    def test_boot_leaves_heater_off(self):
        """Test 1: Boot leaves the heater off."""
        # When no input or initial temp is low, heater should be off after boot
        output = self._run_controller_test(initial_temp=40, initial_heater=False)
        self.assertIn("heater_on: false", output, "Heater should be OFF after boot")

    def test_low_temperature_turns_heater_on(self):
        """Test 2: A low temperature such as 35 drives ACT HEATER ON."""
        # At 35C (below 47 threshold), heater should turn on
        output = self._run_controller_test(initial_temp=35, initial_heater=False,
                                          input_temp=35, expected_heater=True)
        self.assertIn("heater_on: true", output, "Heater should be ON at 35C")

    def test_high_temperature_turns_heater_off(self):
        """Test 3: A temperature above the upper band such as 53 drives ACT HEATER OFF."""
        # At 53C (above 52 threshold), heater should turn off
        output = self._run_controller_test(initial_temp=40, initial_heater=False,
                                          input_temp=53, expected_heater=False)
        self.assertIn("heater_on: false", output, "Heater should be OFF at 53C")

    def test_mid_range_preserves_safe_off(self):
        """Test 4: Inside 47..49, the controller preserves the previous safe actuator state."""
        # Start with heater on, then move to 48C - should preserve safe off
        output = self._run_controller_test(initial_temp=35, initial_heater=True,
                                          input_temp=48, expected_heater=False)
        self.assertIn("heater_on: false", output, "Should preserve safe off at 48C")

    def test_rising_temperature_in_upper_band(self):
        """Test 5: Near the upper band, rising temperature data causes an early ACT HEATER OFF."""
        # Start at 35C with heater on, then move to 51C (rising) - should early off
        output = self._run_controller_test(initial_temp=35, initial_heater=True,
                                          input_temp=51, expected_heater=False)
        self.assertIn("heater_on: false", output, "Should early off at rising 51C")

    def test_malformed_input_turns_heater_off(self):
        """Test 6: Malformed input forces ACT HEATER OFF."""
        # Simulate invalid temperature (-999)
        output = self._run_controller_test(initial_temp=40, initial_heater=True,
                                          input_temp=-999, expected_heater=False)
        self.assertIn("heater_on: false", output, "Should turn off on malformed input")

    def test_stale_sensor_data_turns_heater_off(self):
        """Test 7: Stale sensor data for more than 1000 ms forces ACT HEATER OFF."""
        # Simulate stale data with old timestamp
        output = self._run_controller_test(initial_temp=40, initial_heater=True,
                                          input_temp=-999, expected_heater=False)
        self.assertIn("heater_on: false", output, "Should turn off on stale data")

    def test_temperature_bounds(self):
        """Test: Verify controller responds appropriately across temperature range."""
        # Test various temperatures
        for temp in [30, 45, 51, 53]:
            output = self._run_controller_test(initial_temp=35, initial_heater=True,
                                              input_temp=temp)
            if temp < 47:
                self.assertIn("heater_on: true", output, f"Should heat at {temp}C")
            else:
                self.assertIn("heater_on: false", output, f"Should not heat at {temp}C")


